import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, ActivatedRoute } from '@angular/router';
import { CoursesService } from '../../services';
import { Course, Lesson } from '../../models';

@Component({
  selector: 'app-course-detail',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './course-detail.component.html',
  styleUrls: ['./course-detail.component.scss']
})
export class CourseDetailComponent implements OnInit {
  course: Course | null = null;
  lessons: Lesson[] = [];
  loading = true;

  constructor(
    private route: ActivatedRoute,
    private coursesService: CoursesService
  ) {}

  ngOnInit() {
    const courseId = this.route.snapshot.paramMap.get('id');
    if (courseId) {
      this.loadCourse(courseId);
    }
  }

  loadCourse(courseId: string) {
    this.coursesService.getCourseById(courseId).subscribe(course => {
      this.course = course;
    });

    this.coursesService.getLessonsByCourseId(courseId).subscribe(lessons => {
      this.lessons = lessons;
      this.loading = false;
    });
  }
}
<div class="min-h-screen bg-gray-50 py-8">
  <div class="max-w-7xl mx-auto px-4" *ngIf="course; else loading">
    <div class="bg-white rounded-lg shadow-lg overflow-hidden">
      <div class="md:flex">
        <!-- Course Content -->
        <div class="md:w-2/3 p-8">
          <img [src]="course.thumbnail || '/api/placeholder/600/400'" 
               [alt]="course.title" 
               class="w-full h-64 object-cover rounded-lg mb-6">

          <div class="flex items-center gap-2 mb-4">
            <span class="px-3 py-1 bg-primary-100 text-primary-600 rounded-full text-sm font-medium">
              {{ course.subjectName }}
            </span>
            <span class="px-3 py-1 bg-gray-100 text-gray-600 rounded-full text-sm font-medium">
              {{ course.levelName }}
            </span>
            <span *ngIf="course.isFree" class="px-3 py-1 bg-green-100 text-green-600 rounded-full text-sm font-medium">
              FREE
            </span>
          </div>

          <h1 class="text-3xl font-bold text-gray-900 mb-4">{{ course.title }}</h1>
          <p class="text-gray-600 mb-6">{{ course.description }}</p>

          <div class="flex items-center justify-between mb-6">
            <div class="text-sm text-gray-500">
              <span class="font-medium">{{ course.teacherName }}</span> • {{ course.lessonCount }} lessons
            </div>
            <div class="flex items-center" *ngIf="course.rating">
              <div class="flex text-yellow-400">
                <svg class="w-5 h-5 fill-current" viewBox="0 0 20 20">
                  <path d="M10 15l-5.878 3.09 1.123-6.545L.489 6.91l6.572-.955L10 0l2.939 5.955 6.572.955-4.756 4.635 1.123 6.545z"/>
                </svg>
                <span class="ml-1 text-gray-700">{{ course.rating }}</span>
              </div>
            </div>
          </div>

          <button class="w-full btn-gradient">
            Enroll in Course
          </button>
        </div>

        <!-- Lessons Sidebar -->
        <div class="md:w-1/3 bg-gray-50 p-6">
          <h3 class="text-xl font-semibold text-gray-900 mb-4">Course Lessons</h3>
          <div class="space-y-2">
            <div *ngFor="let lesson of lessons" 
                 class="bg-white p-4 rounded-lg border border-gray-200 hover:border-primary-300 transition-colors">
              <div class="flex items-center gap-3">
                <span class="text-2xl">
                  <span *ngIf="lesson.type === 'video'">🎬</span>
                  <span *ngIf="lesson.type === 'pdf'">📄</span>
                  <span *ngIf="lesson.type === 'summary'">📝</span>
                  <span *ngIf="lesson.type === 'quiz'">❓</span>
                </span>
                <div class="flex-1">
                  <h4 class="font-medium text-gray-900">{{ lesson.title }}</h4>
                  <p class="text-sm text-gray-500">
                    {{ lesson.type }} • {{ lesson.duration }}min
                  </p>
                </div>
                <svg *ngIf="!lesson.isFree" class="w-5 h-5 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"/>
                </svg>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</div>

<ng-template #loading>
  <div class="min-h-screen flex items-center justify-center">
    <div class="text-center">
      <div class="w-16 h-16 border-4 border-primary-200 border-t-primary-600 rounded-full animate-spin"></div>
      <p class="mt-4 text-gray-600">Loading course...</p>
    </div>
  </div>
</ng-template>
